def remove_expense(self, expense_id: int) -> None:
    """Delete an expense by id, raising ExpenseNotFoundError if it doesn't exist."""
    if expense_id not in self._expenses:
        raise ExpenseNotFoundError(f"No expense with id {expense_id}")
    del self._expenses[expense_id]

def remaining_budget(self, category: Category) -> float:
    limit = self.limits.get(category, float("inf"))
    spent = self.store.total_by_category(category)
    return limit - spent

def is_over_budget(self, category: Category) -> bool:
    return self.remaining_budget(category) < 0

def __post_init__(self):
    if self.amount <= 0:
        raise ValueError(f"Expense amount must be positive, got {self.amount}")

def __init__(self):
    self._expenses: dict[int, Expense] = {}
    self._next_id = 1

def add_expense(self, amount, category, description, incurred_on):
    expense = Expense(id=self._next_id, ...)
    self._expenses[expense.id] = expense
    self._next_id += 1
    return expense

from collections import defaultdict

def category_breakdown(store: ExpenseStore) -> dict:
    totals = defaultdict(float)
    for expense in store.list_expenses():
        totals[expense.category] += expense.amount
    return dict(totals)

def monthly_summary(store: ExpenseStore, year: int, month: int) -> float:
    return sum(
        e.amount for e in store.list_expenses()
        if e.incurred_on.year == year and e.incurred_on.month == month
    )

def enforce_budget(self, category: Category) -> None:
    if self.is_over_budget(category):
        raise BudgetExceededError(
            f"Category '{category.value}' is over budget by {-self.remaining_budget(category):.2f}"
        )

